INSERT INTO scenic_spot (name_cn, name_en, desc_cn, desc_en, address, longitude, latitude, open_time, ticket_info, phone, type, total_score, score_count, avg_score, visit_count, collect_count, cover_img, create_time, update_time) VALUES
('百色起义烈士纪念碑', 'Baise Uprising Martyrs Monument', '百色起义烈士纪念碑位于百色市右江区，是为纪念百色起义牺牲的烈士而建。', 'The Baise Uprising Martyrs Monument is located in Youjiang District, Baise City, built to commemorate the martyrs who sacrificed in the Baise Uprising.', '百色市右江区', 106.6185, 23.9067, '08:00-18:00', '免费', '0776-2824102', 1, 46.0, 10, 4.6, 3500, 150, '/images/attraction/4.jpg', NOW(), NOW()),
('红七军军部旧址', 'Former Headquarters of the 7th Red Army', '红七军军部旧址是邓小平、张云逸等老一辈革命家战斗过的地方。', 'The Former Headquarters of the 7th Red Army is where Deng Xiaoping, Zhang Yunyi and other revolutionaries fought.', '百色市右江区', 106.6190, 23.9070, '09:00-17:00', '免费', '0776-2824103', 1, 47.0, 10, 4.7, 2800, 120, '/images/attraction/5.jpg', NOW(), NOW()),
('靖西鹅泉', 'Jingxi Goose Spring', '靖西鹅泉是广西著名的天然泉水，水质清澈见底，周围风景秀丽。', 'Jingxi Goose Spring is a famous natural spring in Guangxi with crystal clear water and beautiful surroundings.', '靖西市', 106.6320, 22.8190, '08:00-18:00', '¥50', '0776-6221189', 2, 45.0, 10, 4.5, 4200, 180, '/images/attraction/6.jpg', NOW(), NOW()),
('靖西旧州古镇', 'Jingxi Jiuzhou Ancient Town', '旧州古镇是广西保存最完整的古镇之一，有着悠久的历史和独特的民族文化。', 'Jiuzhou Ancient Town is one of the best-preserved ancient towns in Guangxi, with a long history and unique ethnic culture.', '靖西市', 106.6330, 22.8200, '全天开放', '免费', '0776-6221190', 3, 44.0, 10, 4.4, 3800, 160, '/images/attraction/7.jpg', NOW(), NOW()),
('乐业罗妹洞', 'Leye Luomei Cave', '罗妹洞是乐业县著名的溶洞景观，洞内钟乳石千姿百态，美不胜收。', 'Luomei Cave is a famous karst cave in Leye County, with various stalactites inside.', '乐业县', 106.4990, 24.7240, '08:30-17:30', '¥60', '0776-7921169', 2, 43.0, 10, 4.3, 2500, 100, '/images/attraction/8.jpg', NOW(), NOW()),
('田东十里莲塘', 'Tiandong Ten-mile Lotus Pond', '田东十里莲塘是广西最大的荷花观赏基地，每年夏季荷花盛开，美不胜收。', 'Tiandong Ten-mile Lotus Pond is the largest lotus viewing base in Guangxi, beautiful when lotus blooms in summer.', '田东县', 107.1170, 23.6670, '06:00-19:00', '¥30', '0776-5221181', 2, 44.0, 10, 4.4, 3200, 140, '/images/attraction/9.jpg', NOW(), NOW()),
('右江民族博物馆', 'Youjiang Ethnic Museum', '右江民族博物馆展示了广西各民族的历史文化和民俗风情。', 'Youjiang Ethnic Museum displays the history, culture and folk customs of various ethnic groups in Guangxi.', '百色市右江区', 106.6200, 23.9080, '09:00-17:00', '免费', '0776-2824104', 3, 45.0, 10, 4.5, 2100, 90, '/images/attraction/10.jpg', NOW(), NOW()),
('百色大王岭', 'Baise Dawang Ridge', '大王岭是百色市著名的自然风景区，山峦叠嶂，森林茂密。', 'Dawang Ridge is a famous natural scenic area in Baise City, with rolling hills and dense forests.', '百色市右江区', 106.6210, 23.9090, '08:00-18:00', '¥80', '0776-2824105', 2, 46.0, 10, 4.6, 3600, 170, '/images/attraction/11.jpg', NOW(), NOW()),
('凌云茶山', 'Lingyun Tea Mountain', '凌云茶山是广西著名的茶叶产区，茶园连绵起伏，景色宜人。', 'Lingyun Tea Mountain is a famous tea production area in Guangxi, with rolling tea gardens and pleasant scenery.', '凌云县', 106.5550, 24.0500, '08:00-18:00', '¥40', '0776-7612181', 2, 44.0, 10, 4.4, 2800, 130, '/images/attraction/12.jpg', NOW(), NOW()),
('平果敢桑石林', 'Pingguo Gansang Stone Forest', '敢桑石林是广西独特的喀斯特地貌景观，石峰林立，形态各异。', 'Gansang Stone Forest is a unique karst landscape in Guangxi, with various stone peaks.', '平果市', 107.5900, 23.3200, '08:00-18:00', '¥50', '0776-5822181', 2, 43.0, 10, 4.3, 2200, 100, '/images/attraction/13.jpg', NOW(), NOW()),
('德保矮马王国', 'Debao Pony Kingdom', '德保矮马王国是广西独特的矮马养殖基地，游客可以近距离接触可爱的矮马。', 'Debao Pony Kingdom is a unique pony breeding base in Guangxi, where visitors can get close to cute ponies.', '德保县', 106.6100, 23.2500, '09:00-17:00', '¥60', '0776-3822181', 3, 45.0, 10, 4.5, 3000, 150, '/images/attraction/14.jpg', NOW(), NOW()),
('那坡黑衣壮风情园', 'Napo Black-clothed Zhuang Cultural Park', '那坡黑衣壮风情园展示了黑衣壮独特的民族文化和生活方式。', 'Napo Black-clothed Zhuang Cultural Park displays the unique ethnic culture and lifestyle of Black-clothed Zhuang.', '那坡县', 105.8300, 23.4000, '08:00-18:00', '¥50', '0776-6822181', 3, 44.0, 10, 4.4, 1800, 80, '/images/attraction/15.jpg', NOW(), NOW()),
('西林宫保府', 'Xilin Gongbao Mansion', '西林宫保府是清代名臣岑毓英的故居，具有很高的历史价值。', 'Xilin Gongbao Mansion is the former residence of Cen Yuying, a famous official in Qing Dynasty.', '西林县', 105.0900, 24.4900, '09:00-17:00', '¥30', '0776-8722181', 3, 43.0, 10, 4.3, 1500, 60, '/images/attraction/16.jpg', NOW(), NOW()),
('隆林各族自治县民族博物馆', 'Longlin Ethnic Autonomous County Museum', '隆林各族自治县民族博物馆展示了苗族、彝族等多个民族的文化。', 'Longlin Ethnic Autonomous County Museum displays the culture of Miao, Yi and other ethnic groups.', '隆林县', 105.3400, 24.7700, '09:00-17:00', '免费', '0776-8202181', 3, 42.0, 10, 4.2, 1200, 50, '/images/attraction/17.jpg', NOW(), NOW()),
('田阳布洛陀文化遗址', 'Tianyang Buluotuo Cultural Site', '布洛陀文化遗址是壮族始祖布洛陀的传说发源地，具有重要的文化意义。', 'Buluotuo Cultural Site is the legendary birthplace of Buluotuo, the ancestor of Zhuang people.', '田阳区', 106.9200, 23.7300, '08:00-18:00', '¥40', '0776-3212181', 3, 44.0, 10, 4.4, 2600, 110, '/images/attraction/18.jpg', NOW(), NOW()),
('靖西三叠岭瀑布', 'Jingxi Sandie Waterfall', '三叠岭瀑布是靖西市著名的瀑布景观，瀑布分三级跌落，蔚为壮观。', 'Sandie Waterfall is a famous waterfall in Jingxi City, falling in three levels, spectacular.', '靖西市', 106.6340, 22.8210, '08:00-18:00', '¥50', '0776-6221191', 2, 46.0, 10, 4.6, 3400, 160, '/images/attraction/19.jpg', NOW(), NOW()),
('乐业穿洞天坑', 'Leye Chuandong Tiankeng', '穿洞天坑是乐业县独特的天坑景观，坑内有天然穿洞，景观奇特。', 'Chuandong Tiankeng is a unique sinkhole in Leye County, with a natural tunnel inside.', '乐业县', 106.5000, 24.7250, '08:30-17:30', '¥70', '0776-7921170', 2, 45.0, 10, 4.5, 2900, 130, '/images/attraction/20.jpg', NOW(), NOW()),
('百色澄碧湖', 'Baise Chengbi Lake', '澄碧湖是百色市最大的人工湖，湖水清澈，周围山峦环抱。', 'Chengbi Lake is the largest artificial lake in Baise City, with clear water surrounded by mountains.', '百色市右江区', 106.6220, 23.9100, '08:00-18:00', '¥40', '0776-2824106', 2, 44.0, 10, 4.4, 3100, 140, '/images/attraction/21.jpg', NOW(), NOW()),
('田东龙须河', 'Tiandong Longxu River', '龙须河是田东县著名的漂流胜地，河水清澈，两岸风景秀丽。', 'Longxu River is a famous rafting destination in Tiandong County, with clear water and beautiful scenery.', '田东县', 107.1180, 23.6680, '08:00-18:00', '¥80', '0776-5221182', 2, 45.0, 10, 4.5, 2700, 120, '/images/attraction/22.jpg', NOW(), NOW()),
('靖西爱布瀑布', 'Jingxi Aibu Waterfall', '爱布瀑布是靖西市的一处原生态瀑布，周围环境清幽，适合徒步。', 'Aibu Waterfall is a pristine waterfall in Jingxi City, with quiet surroundings, suitable for hiking.', '靖西市', 106.6350, 22.8220, '全天开放', '免费', '0776-6221192', 2, 43.0, 10, 4.3, 2000, 90, '/images/attraction/23.jpg', NOW(), NOW()),
('凌云浩坤湖', 'Lingyun Haokun Lake', '浩坤湖是凌云县的高山湖泊，湖水碧绿，周围原始森林茂密。', 'Haokun Lake is an alpine lake in Lingyun County, with green water surrounded by dense forests.', '凌云县', 106.5560, 24.0510, '08:00-18:00', '¥60', '0776-7612182', 2, 46.0, 10, 4.6, 3300, 150, '/images/attraction/24.jpg', NOW(), NOW()),
('百色大码头', 'Baise Grand Wharf', '大码头是百色市的历史遗迹，见证了右江水运的繁荣历史。', 'Grand Wharf is a historical site in Baise City, witnessing the prosperous history of Youjiang water transport.', '百色市右江区', 106.6230, 23.9110, '全天开放', '免费', '0776-2824107', 3, 42.0, 10, 4.2, 1800, 70, '/images/attraction/25.jpg', NOW(), NOW()),
('田阳敢壮山', 'Tianyang Ganzhuang Mountain', '敢壮山是田阳区的著名景点，山上有壮族始祖布洛陀的祭祀场所。', 'Ganzhuang Mountain is a famous attraction in Tianyang District, with a sacrificial site for Buluotuo.', '田阳区', 106.9210, 23.7310, '08:00-18:00', '¥30', '0776-3212182', 3, 44.0, 10, 4.4, 2400, 100, '/images/attraction/26.jpg', NOW(), NOW()),
('平果芦仙湖', 'Pingguo Luxian Lake', '芦仙湖是平果市的人工湖，湖水清澈，是休闲度假的好去处。', 'Luxian Lake is an artificial lake in Pingguo City, with clear water, a good place for leisure.', '平果市', 107.5910, 23.3210, '08:00-18:00', '¥30', '0776-5822182', 2, 43.0, 10, 4.3, 1900, 80, '/images/attraction/27.jpg', NOW(), NOW()),
('德保红叶森林公园', 'Debao Red Leaf Forest Park', '红叶森林公园是德保县的著名景点，秋季红叶满山，景色迷人。', 'Red Leaf Forest Park is a famous attraction in Debao County, with beautiful red leaves in autumn.', '德保县', 106.6110, 23.2510, '08:00-18:00', '¥50', '0776-3822182', 2, 45.0, 10, 4.5, 2800, 130, '/images/attraction/28.jpg', NOW(), NOW()),
('靖西渠洋湖', 'Jingxi Quyang Lake', '渠洋湖是靖西市的高原湖泊，湖水清澈，周围喀斯特地貌独特。', 'Quyang Lake is a plateau lake in Jingxi City, with clear water and unique karst landscape.', '靖西市', 106.6360, 22.8230, '08:00-18:00', '¥40', '0776-6221193', 2, 44.0, 10, 4.4, 2500, 110, '/images/attraction/29.jpg', NOW(), NOW()),
('乐业黄猄洞天坑', 'Leye Huangjing Tiankeng', '黄猄洞天坑是乐业县的天坑群之一，坑内有珍稀动植物。', 'Huangjing Tiankeng is one of the sinkholes in Leye County, with rare animals and plants inside.', '乐业县', 106.5010, 24.7260, '08:30-17:30', '¥80', '0776-7921171', 2, 44.0, 10, 4.4, 2100, 90, '/images/attraction/30.jpg', NOW(), NOW()),
('百色粤东会馆', 'Baise Yuedong Guild Hall', '粤东会馆是百色市的历史建筑，见证了百色商业发展的历史。', 'Yuedong Guild Hall is a historical building in Baise City, witnessing the history of Baise commercial development.', '百色市右江区', 106.6240, 23.9120, '09:00-17:00', '免费', '0776-2824108', 3, 43.0, 10, 4.3, 1600, 60, '/images/attraction/31.jpg', NOW(), NOW()),
('田东龙潭', 'Tiandong Longtan', '龙潭是田东县的天然水潭，潭水清澈见底，周围环境清幽。', 'Longtan is a natural pool in Tiandong County, with crystal clear water and quiet surroundings.', '田东县', 107.1190, 23.6690, '全天开放', '免费', '0776-5221183', 2, 42.0, 10, 4.2, 1400, 50, '/images/attraction/32.jpg', NOW(), NOW()),
('靖西二郎瀑布', 'Jingxi Erlang Waterfall', '二郎瀑布是靖西市的瀑布景观，瀑布落差大，水势汹涌。', 'Erlang Waterfall is a waterfall in Jingxi City, with large drop and surging water.', '靖西市', 106.6370, 22.8240, '08:00-18:00', '¥30', '0776-6221194', 2, 43.0, 10, 4.3, 1700, 70, '/images/attraction/33.jpg', NOW(), NOW()),
('凌云纳灵洞', 'Lingyun Naling Cave', '纳灵洞是凌云县的溶洞景观，洞内钟乳石形态各异，灯光效果绚丽。', 'Naling Cave is a karst cave in Lingyun County, with various stalactites and colorful lighting.', '凌云县', 106.5570, 24.0520, '08:00-18:00', '¥50', '0776-7612183', 2, 44.0, 10, 4.4, 2300, 100, '/images/attraction/34.jpg', NOW(), NOW()),
('百色右江风光带', 'Baise Youjiang Scenic Belt', '右江风光带是百色市的城市景观带，沿江两岸风景优美。', 'Youjiang Scenic Belt is an urban landscape belt in Baise City, with beautiful scenery along the river.', '百色市右江区', 106.6250, 23.9130, '全天开放', '免费', '0776-2824109', 2, 43.0, 10, 4.3, 2000, 80, '/images/attraction/35.jpg', NOW(), NOW()),
('田阳百育古镇', 'Tianyang Baiyu Ancient Town', '百育古镇是田阳区的历史古镇，保存着许多古建筑和民俗文化。', 'Baiyu Ancient Town is a historical town in Tianyang District, preserving many ancient buildings and folk culture.', '田阳区', 106.9220, 23.7320, '全天开放', '免费', '0776-3212183', 3, 42.0, 10, 4.2, 1300, 50, '/images/attraction/36.jpg', NOW(), NOW()),
('平果鸳鸯滩', 'Pingguo Yuanyang Beach', '鸳鸯滩是平果市的漂流景点，河水清澈，适合夏季游玩。', 'Yuanyang Beach is a rafting spot in Pingguo City, with clear water, suitable for summer.', '平果市', 107.5920, 23.3220, '08:00-18:00', '¥60', '0776-5822183', 2, 44.0, 10, 4.4, 2200, 90, '/images/attraction/37.jpg', NOW(), NOW()),
('德保吉星岩', 'Debao Jixing Cave', '吉星岩是德保县的溶洞景观，洞内空间开阔，钟乳石丰富。', 'Jixing Cave is a karst cave in Debao County, with spacious interior and rich stalactites.', '德保县', 106.6120, 23.2520, '08:00-18:00', '¥60', '0776-3822183', 2, 45.0, 10, 4.5, 2600, 120, '/images/attraction/38.jpg', NOW(), NOW()),
('靖西龙邦口岸', 'Jingxi Longbang Port', '龙邦口岸是中越边境的重要口岸，可以体验边境风情。', 'Longbang Port is an important port on the China-Vietnam border, where you can experience border culture.', '靖西市', 106.6380, 22.8250, '08:00-18:00', '免费', '0776-6221195', 3, 43.0, 10, 4.3, 1800, 70, '/images/attraction/39.jpg', NOW(), NOW()),
('乐业火卖村', 'Leye Huomai Village', '火卖村是乐业县的特色村落，保留了传统的壮族建筑和生活方式。', 'Huomai Village is a characteristic village in Leye County, preserving traditional Zhuang architecture and lifestyle.', '乐业县', 106.5020, 24.7270, '全天开放', '免费', '0776-7921172', 3, 42.0, 10, 4.2, 1100, 40, '/images/attraction/40.jpg', NOW(), NOW()),
('百色起义纪念馆新馆', 'New Baise Uprising Memorial Hall', '百色起义纪念馆新馆是百色市新建的红色教育基地，展陈更加丰富。', 'New Baise Uprising Memorial Hall is a newly built red education base in Baise City with richer exhibitions.', '百色市右江区', 106.6260, 23.9140, '09:00-17:00', '免费', '0776-2824110', 1, 47.0, 10, 4.7, 4000, 200, '/images/attraction/41.jpg', NOW(), NOW()),
('田东横山古寨', 'Tiandong Hengshan Ancient Village', '横山古寨是田东县的历史村落，保存着明清时期的古建筑。', 'Hengshan Ancient Village is a historical village in Tiandong County, preserving ancient buildings from Ming and Qing dynasties.', '田东县', 107.1200, 23.6700, '全天开放', '免费', '0776-5221184', 3, 41.0, 10, 4.1, 1000, 40, '/images/attraction/42.jpg', NOW(), NOW());
INSERT INTO food (name_cn, name_en, desc_cn, desc_en, merchant_name, signature_dish, per_capita, business_time, address, longitude, latitude, phone, type, total_score, score_count, avg_score, visit_count, collect_count, cover_img, create_time, update_time) VALUES
('百色老友粉', 'Baise Laoyou Rice Noodle', '百色老友粉是当地特色美食，酸辣可口，深受当地人喜爱。', 'Baise Laoyou Rice Noodle is a local specialty, sour and spicy, loved by locals.', '老友记', '老友粉,酸辣粉', 12, '06:00-22:00', '百色市右江区', 106.6190, 23.9070, '13800138004', 1, 44.0, 10, 4.4, 2800, 110, '/images/food/4.jpg', NOW(), NOW()),
('靖西糍粑', 'Jingxi Glutinous Rice Cake', '靖西糍粑是靖西地区的传统小吃，软糯香甜。', 'Jingxi Glutinous Rice Cake is a traditional snack in Jingxi area, soft and sweet.', '靖西糍粑坊', '糍粑,糯米糍', 5, '07:00-19:00', '靖西市', 106.6320, 22.8190, '13800138005', 1, 43.0, 10, 4.3, 2200, 90, '/images/food/5.jpg', NOW(), NOW()),
('乐业野生菌', 'Leye Wild Mushrooms', '乐业野生菌是当地特色美食，新鲜美味，营养丰富。', 'Leye Wild Mushrooms is a local specialty, fresh, delicious and nutritious.', '乐业菌菇馆', '野生菌火锅,菌菇汤', 68, '10:00-21:00', '乐业县', 106.4990, 24.7240, '13800138006', 2, 46.0, 10, 4.6, 3500, 150, '/images/food/6.jpg', NOW(), NOW()),
('田东柠檬鸭', 'Tiandong Lemon Duck', '田东柠檬鸭是田东县的特色菜，酸香可口，肉质鲜嫩。', 'Tiandong Lemon Duck is a specialty of Tiandong County, sour and fragrant, tender meat.', '柠檬鸭馆', '柠檬鸭,酸笋鸭', 45, '10:00-21:00', '田东县', 107.1170, 23.6670, '13800138007', 2, 45.0, 10, 4.5, 3000, 130, '/images/food/7.jpg', NOW(), NOW()),
('百色烧烤', 'Baise BBQ', '百色烧烤是当地夜宵首选，种类丰富，味道独特。', 'Baise BBQ is the first choice for local late-night snacks, with various types and unique taste.', '百色烧烤城', '烤串,烤鱼,烤鸡', 35, '17:00-02:00', '百色市右江区', 106.6200, 23.9080, '13800138008', 1, 44.0, 10, 4.4, 4200, 180, '/images/food/8.jpg', NOW(), NOW()),
('靖西米饺', 'Jingxi Rice Dumpling', '靖西米饺是靖西地区的传统美食，皮薄馅多，口感独特。', 'Jingxi Rice Dumpling is a traditional food in Jingxi area, thin skin with lots of filling.', '靖西米饺店', '米饺,水晶饺', 8, '06:00-20:00', '靖西市', 106.6330, 22.8200, '13800138009', 1, 43.0, 10, 4.3, 2500, 100, '/images/food/9.jpg', NOW(), NOW()),
('凌云白毫茶', 'Lingyun Baihao Tea', '凌云白毫茶是广西名茶，茶汤清澈，香气高雅。', 'Lingyun Baihao Tea is a famous tea in Guangxi, with clear tea soup and elegant aroma.', '凌云茶庄', '白毫茶,绿茶', 50, '08:00-20:00', '凌云县', 106.5550, 24.0500, '13800138010', 3, 47.0, 10, 4.7, 3800, 170, '/images/food/10.jpg', NOW(), NOW()),
('平果卷粉', 'Pingguo Rice Roll', '平果卷粉是平果市的特色小吃，口感爽滑，配料丰富。', 'Pingguo Rice Roll is a specialty snack in Pingguo City, smooth taste with rich toppings.', '平果卷粉店', '卷粉,肠粉', 10, '06:00-20:00', '平果市', 107.5900, 23.3200, '13800138011', 1, 42.0, 10, 4.2, 2000, 80, '/images/food/11.jpg', NOW(), NOW()),
('德保猪血肠', 'Debao Pig Blood Sausage', '德保猪血肠是德保县的特色美食，口感独特，营养丰富。', 'Debao Pig Blood Sausage is a specialty of Debao County, unique taste and nutritious.', '德保血肠店', '猪血肠,糯米肠', 15, '06:00-19:00', '德保县', 106.6100, 23.2500, '13800138012', 1, 44.0, 10, 4.4, 2700, 110, '/images/food/12.jpg', NOW(), NOW()),
('那坡黑粽', 'Napo Black Zongzi', '那坡黑粽是那坡县的特色美食，用黑糯米制作，口感独特。', 'Napo Black Zongzi is a specialty of Napo County, made with black glutinous rice, unique taste.', '那坡黑粽坊', '黑粽,糯米粽', 8, '06:00-18:00', '那坡县', 105.8300, 23.4000, '13800138013', 3, 43.0, 10, 4.3, 1800, 70, '/images/food/13.jpg', NOW(), NOW()),
('西林麻鸭', 'Xilin Ma Duck', '西林麻鸭是西林县的特色美食，肉质鲜嫩，味道鲜美。', 'Xilin Ma Duck is a specialty of Xilin County, tender meat and delicious taste.', '西林麻鸭馆', '麻鸭,白切鸭', 55, '10:00-21:00', '西林县', 105.0900, 24.4900, '13800138014', 2, 45.0, 10, 4.5, 2300, 100, '/images/food/14.jpg', NOW(), NOW()),
('隆林黑糯米', 'Longlin Black Glutinous Rice', '隆林黑糯米是隆林县的特产，营养丰富，可制作多种美食。', 'Longlin Black Glutinous Rice is a specialty of Longlin County, nutritious and can make various foods.', '隆林黑糯米坊', '黑糯米饭,黑糯米糕', 12, '06:00-19:00', '隆林县', 105.3400, 24.7700, '13800138015', 3, 42.0, 10, 4.2, 1500, 60, '/images/food/15.jpg', NOW(), NOW()),
('田阳烧猪', 'Tianyang Roast Pig', '田阳烧猪是田阳区的特色美食，皮脆肉嫩，香气四溢。', 'Tianyang Roast Pig is a specialty of Tianyang District, crispy skin and tender meat.', '田阳烧猪店', '烧猪,烧肉', 80, '10:00-21:00', '田阳区', 106.9200, 23.7300, '13800138016', 2, 46.0, 10, 4.6, 3200, 140, '/images/food/16.jpg', NOW(), NOW()),
('靖西五色糯米饭', 'Jingxi Five-color Glutinous Rice', '靖西五色糯米饭是靖西市的传统美食，色彩鲜艳，口感软糯。', 'Jingxi Five-color Glutinous Rice is a traditional food in Jingxi City, colorful and soft.', '靖西糯米饭店', '五色糯米饭,糯米饭', 10, '06:00-19:00', '靖西市', 106.6340, 22.8210, '13800138017', 1, 44.0, 10, 4.4, 2600, 110, '/images/food/17.jpg', NOW(), NOW()),
('乐业核桃', 'Leye Walnut', '乐业核桃是乐业县的特产，营养丰富，口感香脆。', 'Leye Walnut is a specialty of Leye County, nutritious and crispy.', '乐业核桃店', '核桃,核桃糖', 30, '08:00-20:00', '乐业县', 106.5000, 24.7250, '13800138018', 3, 43.0, 10, 4.3, 1900, 80, '/images/food/18.jpg', NOW(), NOW()),
('百色螺蛳粉', 'Baise Snail Rice Noodle', '百色螺蛳粉是当地特色美食，汤底浓郁，配料丰富。', 'Baise Snail Rice Noodle is a local specialty, rich soup base with various toppings.', '百色螺蛳粉店', '螺蛳粉,酸辣粉', 15, '06:00-22:00', '百色市右江区', 106.6210, 23.9090, '13800138019', 1, 45.0, 10, 4.5, 3800, 160, '/images/food/19.jpg', NOW(), NOW()),
('田东香蕉', 'Tiandong Banana', '田东香蕉是田东县的特产，香甜可口，营养丰富。', 'Tiandong Banana is a specialty of Tiandong County, sweet and nutritious.', '田东香蕉园', '香蕉,香蕉干', 10, '08:00-19:00', '田东县', 107.1180, 23.6680, '13800138020', 3, 44.0, 10, 4.4, 2400, 100, '/images/food/20.jpg', NOW(), NOW()),
('靖西大果山楂', 'Jingxi Large Hawthorn', '靖西大果山楂是靖西市的特产，酸甜可口，可制作多种食品。', 'Jingxi Large Hawthorn is a specialty of Jingxi City, sweet and sour, can make various foods.', '靖西山楂店', '山楂,山楂糕', 15, '08:00-19:00', '靖西市', 106.6350, 22.8220, '13800138021', 3, 42.0, 10, 4.2, 1600, 60, '/images/food/21.jpg', NOW(), NOW()),
