('百色油茶', 'Baise Oil Tea', '百色油茶是当地特色饮品，香浓可口，具有保健功效。', 'Baise Oil Tea is a local specialty drink, fragrant with health benefits.', '百色油茶馆', '油茶,油茶粑', 10, '06:00-20:00', '百色市右江区', 106.6230, 23.9110, '13800138029', 1, 43.0, 10, 4.3, 2000, 80, '/images/food/29.jpg', NOW(), NOW()),
('田东圣女果', 'Tiandong Cherry Tomato', '田东圣女果是田东县的特产，酸甜可口，营养丰富。', 'Tiandong Cherry Tomato is a specialty of Tiandong County, sweet and sour, nutritious.', '田东圣女果园', '圣女果,小番茄', 12, '08:00-19:00', '田东县', 107.1190, 23.6690, '13800138030', 3, 43.0, 10, 4.3, 1700, 70, '/images/food/30.jpg', NOW(), NOW()),
('靖西壮锦', 'Jingxi Zhuang Brocade', '靖西壮锦是靖西市的特色工艺品，图案精美，色彩艳丽。', 'Jingxi Zhuang Brocade is a specialty craft in Jingxi City, beautiful patterns and colors.', '靖西壮锦坊', '壮锦,民族织锦', 50, '08:00-18:00', '靖西市', 106.6370, 22.8240, '13800138031', 3, 44.0, 10, 4.4, 1400, 60, '/images/food/31.jpg', NOW(), NOW()),
('凌云白毫茶糕', 'Lingyun Baihao Tea Cake', '凌云白毫茶糕是用白毫茶制作的特色糕点，茶香浓郁。', 'Lingyun Baihao Tea Cake is a specialty pastry made with Baihao tea, strong tea aroma.', '凌云茶糕店', '茶糕,绿茶糕', 15, '08:00-20:00', '凌云县', 106.5570, 24.0520, '13800138032', 4, 43.0, 10, 4.3, 1500, 60, '/images/food/32.jpg', NOW(), NOW()),
('百色米粉', 'Baise Rice Noodle', '百色米粉是当地特色主食，口感爽滑，配料丰富。', 'Baise Rice Noodle is a local staple food, smooth texture with rich toppings.', '百色米粉店', '米粉,汤粉,干拌粉', 10, '06:00-21:00', '百色市右江区', 106.6240, 23.9120, '13800138033', 1, 44.0, 10, 4.4, 3400, 140, '/images/food/33.jpg', NOW(), NOW()),
('田阳番茄', 'Tianyang Tomato', '田阳番茄是田阳区的特产，品质优良，远销国内外。', 'Tianyang Tomato is a specialty of Tianyang District, high quality, sold at home and abroad.', '田阳番茄园', '番茄,番茄酱', 8, '08:00-19:00', '田阳区', 106.9220, 23.7320, '13800138034', 3, 42.0, 10, 4.2, 1900, 80, '/images/food/34.jpg', NOW(), NOW()),
('平果豆腐花', 'Pingguo Tofu Pudding', '平果豆腐花是平果市的特色甜品，嫩滑可口。', 'Pingguo Tofu Pudding is a specialty dessert in Pingguo City, tender and smooth.', '平果豆腐花店', '豆腐花,豆花', 5, '06:00-22:00', '平果市', 107.5920, 23.3220, '13800138035', 4, 43.0, 10, 4.3, 2300, 90, '/images/food/35.jpg', NOW(), NOW()),
('德保脐橙', 'Debao Navel Orange', '德保脐橙是德保县的特产，果肉饱满，香甜多汁。', 'Debao Navel Orange is a specialty of Debao County, full flesh, sweet and juicy.', '德保脐橙园', '脐橙,橙子', 10, '08:00-19:00', '德保县', 106.6120, 23.2520, '13800138036', 3, 45.0, 10, 4.5, 2800, 120, '/images/food/36.jpg', NOW(), NOW()),
('靖西凉粽', 'Jingxi Cold Zongzi', '靖西凉粽是靖西市的传统美食，夏季食用清凉解暑。', 'Jingxi Cold Zongzi is a traditional food in Jingxi City, refreshing for summer.', '靖西凉粽店', '凉粽,碱水粽', 6, '06:00-19:00', '靖西市', 106.6380, 22.8250, '13800138037', 1, 42.0, 10, 4.2, 1600, 60, '/images/food/37.jpg', NOW(), NOW()),
('乐业茶叶', 'Leye Tea', '乐业茶叶是乐业县的特产，香气高雅，口感醇厚。', 'Leye Tea is a specialty of Leye County, elegant aroma and mellow taste.', '乐业茶庄', '绿茶,红茶', 40, '08:00-20:00', '乐业县', 106.5020, 24.7270, '13800138038', 3, 44.0, 10, 4.4, 2000, 80, '/images/food/38.jpg', NOW(), NOW()),
('百色糯米饭', 'Baise Glutinous Rice', '百色糯米饭是当地特色主食，软糯可口，配料丰富。', 'Baise Glutinous Rice is a local staple food, soft with rich toppings.', '百色糯米饭店', '糯米饭,五色糯米饭', 8, '06:00-20:00', '百色市右江区', 106.6250, 23.9130, '13800138039', 1, 43.0, 10, 4.3, 2500, 100, '/images/food/39.jpg', NOW(), NOW()),
('田东荔枝', 'Tiandong Lychee', '田东荔枝是田东县的特产，果肉饱满，香甜可口。', 'Tiandong Lychee is a specialty of Tiandong County, full flesh, sweet and delicious.', '田东荔枝园', '荔枝,荔枝干', 15, '08:00-19:00', '田东县', 107.1200, 23.6700, '13800138040', 3, 44.0, 10, 4.4, 2100, 90, '/images/food/40.jpg', NOW(), NOW());
INSERT INTO news (title_cn, title_en, content_cn, content_en, cover_img, read_count, create_time, update_time) VALUES
('百色红色旅游发展报告', 'Baise Red Tourism Development Report', '百色市红色旅游资源丰富，近年来发展迅速，成为广西重要的红色旅游目的地。', 'Baise City has rich red tourism resources and has developed rapidly in recent years, becoming an important red tourism destination in Guangxi.', '/images/news/3.jpg', 1500, NOW(), NOW()),
('靖西边境旅游攻略', 'Jingxi Border Tourism Guide', '靖西市位于中越边境，拥有独特的边境风情和自然景观，是边境旅游的热门目的地。', 'Jingxi City is located on the China-Vietnam border, with unique border culture and natural landscapes, a popular destination for border tourism.', '/images/news/4.jpg', 1200, NOW(), NOW()),
('乐业天坑探险记', 'Leye Tiankeng Adventure Story', '乐业天坑群是世界上最大的天坑群之一，探险爱好者可以在这里体验独特的地下世界。', 'Leye Tiankeng Group is one of the largest sinkhole groups in the world, where adventure lovers can experience a unique underground world.', '/images/news/5.jpg', 1800, NOW(), NOW()),
('百色美食文化节开幕', 'Baise Food Culture Festival Opens', '百色美食文化节盛大开幕，汇集了百色各地的特色美食，让游客大饱口福。', 'Baise Food Culture Festival grandly opens, gathering specialty foods from all over Baise, letting tourists enjoy a feast.', '/images/news/6.jpg', 2000, NOW(), NOW()),
('田东芒果节即将举办', 'Tiandong Mango Festival Coming Soon', '田东芒果节即将举办，届时将有各种芒果品种展示和品尝活动。', 'Tiandong Mango Festival is coming soon, with various mango varieties display and tasting activities.', '/images/news/7.jpg', 1600, NOW(), NOW()),
('百色旅游交通指南', 'Baise Tourism Transportation Guide', '详细介绍百色市内及周边景点的交通方式，帮助游客更好地规划行程。', 'Detailed introduction to transportation in Baise City and surrounding attractions, helping tourists plan their trips better.', '/images/news/8.jpg', 1100, NOW(), NOW()),
('靖西壮族风情体验', 'Jingxi Zhuang Culture Experience', '靖西市是壮族聚居地，游客可以在这里体验原汁原味的壮族文化。', 'Jingxi City is a Zhuang settlement, where tourists can experience authentic Zhuang culture.', '/images/news/9.jpg', 1400, NOW(), NOW()),
('乐业户外运动推荐', 'Leye Outdoor Sports Recommendations', '乐业县拥有丰富的户外运动资源，包括徒步、攀岩、探险等多种项目。', 'Leye County has rich outdoor sports resources, including hiking, rock climbing, adventure and other activities.', '/images/news/10.jpg', 900, NOW(), NOW()),
('百色民宿推荐', 'Baise Homestay Recommendations', '精选百色市及周边的特色民宿，让游客体验当地的民俗风情。', 'Selected characteristic homestays in and around Baise City, letting tourists experience local folk customs.', '/images/news/11.jpg', 1300, NOW(), NOW()),
('田东农业观光游', 'Tiandong Agricultural Tourism', '田东县是广西重要的农业县，游客可以在这里体验农业观光和采摘乐趣。', 'Tiandong County is an important agricultural county in Guangxi, where tourists can experience agricultural tourism and picking fun.', '/images/news/12.jpg', 800, NOW(), NOW()),
('百色红色教育基地介绍', 'Introduction to Baise Red Education Bases', '百色市拥有多个红色教育基地，是开展爱国主义教育的重要场所。', 'Baise City has multiple red education bases, important places for patriotic education.', '/images/news/13.jpg', 1700, NOW(), NOW()),
('靖西自然风光摄影指南', 'Jingxi Natural Scenery Photography Guide', '靖西市拥有壮丽的自然风光，是摄影爱好者的天堂。', 'Jingxi City has magnificent natural scenery, a paradise for photography lovers.', '/images/news/14.jpg', 1000, NOW(), NOW()),
('乐业地质科普游', 'Leye Geological Science Tour', '乐业县拥有独特的地质景观，是开展地质科普教育的理想场所。', 'Leye County has unique geological landscapes, an ideal place for geological science education.', '/images/news/15.jpg', 750, NOW(), NOW()),
('百色特色小吃盘点', 'Baise Specialty Snacks Review', '盘点百色市的各种特色小吃，让游客不虚此行。', 'Review of various specialty snacks in Baise City, making the trip worthwhile for tourists.', '/images/news/16.jpg', 1900, NOW(), NOW()),
('田东水果采摘季', 'Tiandong Fruit Picking Season', '田东县水果资源丰富，不同季节有不同的水果可以采摘。', 'Tiandong County has rich fruit resources, with different fruits available for picking in different seasons.', '/images/news/17.jpg', 850, NOW(), NOW());
